mapper.select:
SELECT p.PLC_NO AS plcNo, p.PLC_NAME AS plcName, p.PLC_ADDR AS plcAddr, p.PLC_AVG_RATING AS plcAvgRating, p.PLC_USE_YN AS plcUseYn /* 🚀 혹시 모르니 데이터에 상태값 포함 */ FROM PLACE p LEFT JOIN PLACE_PLAY pl ON p.PLC_NO = pl.PLAY_PLC_NO WHERE p.PLC_CAT_CD = 'PLC002'
AND p.PLC_USE_YN = 'N'
/* 전체 조회 */
AND p.PLC_USE_YN = 'Y'
AND p.PLC_RGN_CD = #{rgnCd}
ORDER BY p.PLC_NO DESC LIMIT #{offset}, #{size}

SELECT p.PLC_NO AS plcNo, p.PLC_ID AS plcId, p.PLC_RGN_CD AS plcRgnCd, p.PLC_NAME AS plcName, p.PLC_ADDR AS plcAddr, p.PLC_LAT AS plcLat, p.PLC_LOT AS plcLot, p.PLC_TELNO AS plcTelno, p.PLC_OVERVIEW AS plcOverview, p.PLC_MAIN_IMG_URL AS plcMainImgUrl, p.PLC_THUM_IMG_URL AS plcThumImgUrl, p.PLC_FLT_CD AS plcFltCd, p.PLC_AVG_RATING AS plcAvgRating, p.PLC_REVIEW_CNT AS plcReviewCnt, pl.PLAY_INFOCENTER AS playInfocenter, pl.PLAY_PARKING AS playParking, pl.PLAY_RESTDATE AS playRestdate, pl.PLAY_USETIME AS playUsetime, pl.PLAY_EVENT_START AS playEventStart, pl.PLAY_EVENT_END AS playEventEnd FROM PLACE p LEFT JOIN PLACE_PLAY pl ON p.PLC_NO = pl.PLAY_PLC_NO WHERE p.PLC_CAT_CD = 'PLC002'
AND p.PLC_RGN_CD = #{rgnCd}
ORDER BY p.PLC_NO DESC
